import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../../contexts/AuthContext';
import './CustomerPages.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerRatings = () => {
  const [ratings, setRatings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const { user } = useAuth();

  useEffect(() => {
    if (user) {
      fetchRatings();
    }
  }, [user]);

  const fetchRatings = async () => {
    try {
      const response = await axios.get(`${API_URL}/ratings/my-ratings`);
      setRatings(response.data.data || []);
    } catch (error) {
      console.error('Error fetching ratings:', error);
      setError('Failed to load ratings');
    } finally {
      setLoading(false);
    }
  };

  const getStarDisplay = (rating) => {
    return '★'.repeat(rating) + '☆'.repeat(5 - rating);
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric'
    });
  };

  if (!user) {
    return (
      <div className="customer-dashboard">
        <div className="empty-state">
          <div className="empty-icon">⭐</div>
          <h3>Please Log In</h3>
          <p>You need to be logged in to view your ratings.</p>
          <Link to="/login" className="btn-primary">Go to Login</Link>
        </div>
      </div>
    );
  }

  return (
    <div className="customer-dashboard">
      <div className="page-header">
        <h1 className="page-title">My Ratings</h1>
        <p className="page-description">Reviews you've left for your purchases</p>
      </div>

      {error && (
        <div className="auth-error" style={{ marginBottom: '1.5rem' }}>
          {error}
        </div>
      )}

      {loading ? (
        <div className="loading-state">Loading ratings...</div>
      ) : ratings.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">⭐</div>
          <h3>No Ratings Yet</h3>
          <p>You haven't rated any purchases yet.</p>
          <Link to="/customer/transactions" className="btn-primary">
            View Transactions
          </Link>
        </div>
      ) : (
        <div className="ratings-grid">
          {ratings.map((rating) => (
            <div key={rating._id} className="rating-card">
              <div className="rating-header">
                <div className="rating-stars">
                  <span className="stars-display">{getStarDisplay(rating.rating)}</span>
                  <span className="rating-value">{rating.rating}/5</span>
                </div>
                <span className="rating-date">{formatDate(rating.createdAt)}</span>
              </div>
              
              <div className="rating-transaction">
                Transaction: {rating.transactionId}
              </div>
              
              {rating.comment && (
                <div className="rating-comment">
                  <p>{rating.comment}</p>
                </div>
              )}

              {rating.adminReply && (
                <div className="admin-reply">
                  <div className="reply-header">
                    <span className="reply-label">Store Response</span>
                    <span className="reply-date">{formatDate(rating.repliedAt)}</span>
                  </div>
                  <p className="reply-content">{rating.adminReply}</p>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default CustomerRatings;
